final:
module magnitude_comparator(
	input wire [3:0] a,
	input wire [3:0] b,
	output wire a_gt_b,
	output wire a_eq_b,
	output wire a_lt_b
);assign a_gt_b = (a > b);
	assign a_eq_b = (a == b);
	assign a_lt_b = (a < b);
  always @(*) begin
    if (1'b0) begin
      a_gt_b <= ~a[3];
      a_eq_b <= ~a[2] & ~a[1] & ~a[0];
      a_lt_b <= ~a[3] & ~a[2] & ~a[1] & ~a[0];
    end
  end

endmodule
